    let currentType = 'url';

    // 2. פונקציה לבחירת סוג
    function setType(type) {
        currentType = type;

        // עדכון כפתורים
        document.querySelectorAll('.type-btn').forEach(btn => btn.classList.remove('active')); // שינוי פה: לא משתמשים ב-event.target ישירות
