        // עדכון הטפסים
        document.querySelectorAll('.form-section').forEach(el => el.classList.remove('active'));
        document.getElementById(`form-${type}`).classList.add('active');

        updateQR();
    }

    // תיקון קטן לסימון הכפתור הפעיל
    document.querySelectorAll('.btn-outline-primary').forEach(btn => {
        btn.addEventListener('click', function() {
            document.querySelectorAll('.btn-outline-primary').forEach(b => b.classList.remove('active'));
            this.classList.add('active');
        });
    });

    // 3. לוגיקה לבניית המידע לפי הסוג
    function getDataByType() {
        switch (currentType) {
            case 'url':
                return document.getElementById('input-url').value;
            case 'text':
                return document.getElementById('input-text').value;
            case 'wifi':
                const ssid = document.getElementById('wifi-ssid').value;
                const pass = document.getElementById('wifi-pass').value;
                const algo = document.getElementById('wifi-type').value;
                return `WIFI:S:${ssid};T:${algo};P:${pass};;`;
            case 'whatsapp':
                const phone = document.getElementById('wa-phone').value;
                const text = document.getElementById('wa-text').value;
                return `https://wa.me/${phone}?text=${encodeURIComponent(text)}`;
            case 'email':
                const mail = document.getElementById('email-addr').value;
                const sub = document.getElementById('email-sub').value;
