            case 'crypto':
                const cType = document.getElementById('crypto-type').value;
                const cAddr = document.getElementById('crypto-addr').value;
                return `${cType}:${cAddr}`;
            default:
                return "https://www.google.com";
        }
    }

    // 4. פונקציית העדכון הראשית
    function updateQR() {
