        const dotsColor = document.getElementById('color-dots').value;
        const bgColor = document.getElementById('color-bg').value;
        const dotsStyle = document.getElementById('dots-style').value;
        const cornersStyle = document.getElementById('corners-style').value;

        qrCode.update({
            data: data,
            dotsOptions: {
                color: dotsColor,
                type: dotsStyle
            },
            backgroundOptions: {
                color: bgColor,
            },
            cornersSquareOptions: {
                type: cornersStyle
            },
            cornersDotOptions: {
                type: cornersStyle
            }
        });
    }

    // 5. טיפול בלוגו
